import { updateTableSettings } from '../firebase/settingsActions'; // Import updateTableSettings
import { 
  Bell, Utensils, Moon, RefreshCw, FileText, CreditCard, 
  RotateCcw, Clock, Users, Timer
} from 'lucide-react';
import Card from './Card';

const TimeSinceInteraction = ({ timestamp }) => {
  const [timeStr, setTimeStr] = useState("0m");
  useEffect(() => {
    if (!timestamp) return;
    const calc = () => {
      const date = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
      const diffMins = Math.max(0, Math.floor((new Date() - date) / 60000)); // Ensure non-negative
      setTimeStr(diffMins < 60 ? `${diffMins}m` : `${Math.floor(diffMins/60)}h ${diffMins%60}m`);
    };
    calc();
    const inv = setInterval(calc, 60000);
    return () => clearInterval(inv);
  }, [timestamp]);
  return <span className="text-[10px] font-black text-gray-500 flex items-center gap-1 uppercase"><Clock size={10}/> {timeStr}</span>;
};

const TotalTime = ({ timestamp }) => {
  const [timeStr, setTimeStr] = useState("0m");
  useEffect(() => {
    if (!timestamp) return;
    const calc = () => {
      const date = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
      const diffMins = Math.max(0, Math.floor((new Date() - date) / 60000));
      setTimeStr(diffMins < 60 ? `${diffMins}m` : `${Math.floor(diffMins/60)}h ${diffMins%60}m`);
    };
    calc();
    const inv = setInterval(calc, 60000);
    return () => clearInterval(inv);
  }, [timestamp]);
  return <span className="text-[10px] font-black text-mictlan-gold flex items-center gap-1 uppercase"><Timer size={10}/> {timeStr}</span>;
}

const ToggleButton = ({ active, icon, onClick, color, bgActive }) => (
  <button 
    onClick={(e) => { e.stopPropagation(); onClick(); }}
    className={`p-3 rounded-xl flex justify-center items-center transition-all border ${
      active 
      ? `${bgActive} ${color} border-mictlan-gold shadow-[0_0_10px_rgba(212,175,55,0.3)]` 
      : 'bg-black/40 text-gray-600 border-gray-800 hover:border-gray-600'
    }`}
  >
    {icon}
  </button>
);

